var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SHINNARAE_EXTRA_NULL_NULL","text":{"KOREA":"미나야, 좀 가까이 붙어 봐. 빨리빨리.","JPN":"ミナ、もっと近寄ってよ。早く早く。","ENG":"Stand a little closer, Mina. Hurry.","TWN":"米娜，靠近一點。快點快點！"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHINNARAE_EXTRA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SHINNAJIN_EXTRA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_STUDENT_NULL","text":{"KOREA":"아니, 그게...... 난 이런 거 별로라니까.","JPN":"いや、だから……　私はこういうの苦手だって。","ENG":"But I... I’m really not into this sort of thing.","TWN":"咦，那個……我不太喜歡。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_STUDENT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SHINNAJIN_EXTRA_NULL_NULL","text":{"KOREA":"마, 맞아. 누나. 미나 누나도 싫다잖......","JPN":"そ、そうだよ、姉ちゃん。　ミナさんも嫌がってるじゃん。","ENG":"See, sis? Mina said she doesn’t like it either...","TWN":"對、對啊，姐姐，米娜姐姐都說她不喜歡了。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHINNARAE_EXTRA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SHINNAJIN_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SHINNAJIN_EXTRA_NULL_NULL","text":{"KOREA":" 윽!","JPN":"うっ！","ENG":" Ugh!","TWN":"嗚！"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHINNARAE_EXTRA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SHINNAJIN_EXTRA_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL"},{"id":"L10_1","type":"dialog","speaker":"SHINNARAE_EXTRA_NULL_NULL","text":{"KOREA":"어휴, 이 쑥맥아...... 보는 내가 더 답답하다.","JPN":"まったくもう、これだから根性なしは……見てるこっちがもどかしい。","ENG":"Don’t be such a chicken. No wonder you can’t get any girls.","TWN":"唉，這笨蛋……看得我都鬱悶起來了。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHINNARAE_EXTRA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SHINNAJIN_EXTRA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"SHINNARAE_EXTRA_NULL_NULL","text":{"KOREA":"넌 그냥 입 다물고 이 누나가 시키는 대로나 해. 알았지?","JPN":"いいから、あんたは黙って私に言われたとおりにしなさい。わかったわね？","ENG":"You just shut up and do as I say. Got that?","TWN":"你只要閉上嘴，照姐姐說的做就好，懂嗎？"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHINNARAE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHINNAJIN_EXTRA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"SHINNARAE_EXTRA_NULL_NULL","text":{"KOREA":"자자, 미나야. 여기 서서 카메라 쪽 보면 돼.","JPN":"さあ、ミナ。ここに立ってカメラの方を見て。","ENG":"Now, Mina. Stand over here and look at the camera.","TWN":"來，米娜，妳站在這裡，看著鏡頭就可以了。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHINNAJIN_EXTRA_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"SHINNARAE_EXTRA_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"YOOMINA_FENRIR_STUDENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_STUDENT_NULL","text":{"KOREA":"......왜 배경이 하트야?","JPN":"……なんで背景がハートなの？","ENG":"Why is there a heart in the background?","TWN":"……為什麼背景是心形的？"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHINNAJIN_EXTRA_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"SHINNARAE_EXTRA_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"YOOMINA_FENRIR_STUDENT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"SHINNARAE_EXTRA_NULL_NULL","text":{"KOREA":"사소한 건 신경 쓰지 말고!","JPN":"そんな些細なことは気にしない気にしない！","ENG":"Don’t worry about the details!","TWN":"這種小事就不用管了！"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHINNAJIN_EXTRA_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"SHINNARAE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"YOOMINA_FENRIR_STUDENT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"SHINNARAE_EXTRA_NULL_NULL","text":{"KOREA":"자, 찍는다! 치─즈!","JPN":"さぁ、撮るよ！　チーズ！","ENG":"Okay, here we go! Say cheese!","TWN":"來，要拍囉！起～～司！"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHINNAJIN_EXTRA_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"SHINNARAE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"YOOMINA_FENRIR_STUDENT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"SHINNARAE_EXTRA_NULL_NULL","text":{"KOREA":"오우. 잘 나왔네.","JPN":"おお、よく撮れてる。","ENG":"Ooh. That’s a nice picture.","TWN":"噢，拍得真不錯。"},"stage":{"bg":"MAINSTREAM_320010","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SHINNARAE_EXTRA_NULL_NULL","text":{"KOREA":"어때, 미나야? 네가 봐도 잘 어울리는 것 같지 않니?","JPN":"ミナ、どう？　ミナから見てもお似合いだよね？","ENG":"What do you say, Mina? You guys look great together, don’t you think?","TWN":"怎麼樣，米娜？妳不覺得很好看嗎？"},"stage":{"bg":"MAINSTREAM_320010","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SHINNAJIN_EXTRA_NULL_NULL","text":{"KOREA":"아, 누나 진짜!","JPN":"もう、姉ちゃんのバカ！","ENG":"Come on, sis!","TWN":"啊、姐姐妳真是的！"},"stage":{"bg":"MAINSTREAM_320010","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_STUDENT_NULL","text":{"KOREA":"그다지 별로?","JPN":"いや、べつに？","ENG":"Meh, I don’t know.","TWN":"不怎麼樣吧？"},"stage":{"bg":"MAINSTREAM_320010","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_STUDENT_NULL","text":{"KOREA":"나진이는 키가 작아서 같이 찍을 때 밸런스도 잘 안 맞고......","JPN":"タクミは背が低いから、ツーショットだとバランスも今ひとつだし……","ENG":"Najin looks too short next to me in the photo...","TWN":"納金長太矮，我們一起拍照的話，看起來就不太均衡……"},"stage":{"bg":"MAINSTREAM_320010","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SHINNAJIN_EXTRA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"MAINSTREAM_320010","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SHINNARAE_EXTRA_NULL_NULL","text":{"KOREA":"......한 명은 쑥맥이고 한 명은 둔치라니.","JPN":"……片方は根性なしで、もう片方は鈍感か。","ENG":"I can’t believe I have to deal with a chicken AND a turkey...","TWN":"……一個是笨蛋，一個又這麼冷淡……"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHINNARAE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHINNAJIN_EXTRA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L33_1","type":"dialog","speaker":"SHINNARAE_EXTRA_NULL_NULL","text":{"KOREA":"동생아. 안타깝지만 너 이번 생은 가망 없겠다.","JPN":"弟よ、残念だけどその想いは現世では叶わないかもね。","ENG":"Sorry, little brother. I don’t think you’ll ever have a shot with this one.","TWN":"我的好弟弟啊，真是太遺憾了，我這輩子大概都不會再指望你了。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHINNARAE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHINNAJIN_EXTRA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L34_1","type":"dialog","speaker":"SHINNAJIN_EXTRA_NULL_NULL","text":{"KOREA":"아, 쓸데없는 소리하지 말고 빨리 가! 이러다 학교 늦겠어!","JPN":"余計なこと言わないで早く行けよ！　学校に遅れるぞ！","ENG":"Cut the crap and let’s get going! We're going to be late to school!","TWN":"不要廢話了，快走吧！再這樣下去，學校會遲到的！"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHINNARAE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHINNAJIN_EXTRA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L35_1","type":"dialog","speaker":"SHINNAJIN_EXTRA_NULL_NULL","text":{"KOREA":"대체 시험을 어떻게 쳤길래 주말 강제 보충 수업 같은 걸 받는 거야?","JPN":"週末に出席必須の補習だなんて、テスト結果どんだけひどかったんだ？","ENG":"How hard did you fail the test that you have to go to make up classes on weekends?!","TWN":"妳考試到底考得有多爛，週末才要參加強制補習啊？"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHINNARAE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHINNAJIN_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SHINNAJIN_EXTRA_NULL_NULL","text":{"KOREA":"애초에 누나는 입시반도 아니잖아?!","JPN":"そもそも姉ちゃんは進学クラスでもないだろ？","ENG":"You’re not even taking any AP classes!","TWN":"姐姐當初不是有通過入學考試嗎？！"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHINNARAE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHINNAJIN_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"SHINNARAE_EXTRA_NULL_NULL","text":{"KOREA":"그그그그그, 그건!!","JPN":"そそそそそ、それは！！","ENG":"W-well, that’s because...","TWN":"那那那那那是因為！"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHINNARAE_EXTRA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SHINNAJIN_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"SHINNARAE_EXTRA_NULL_NULL","text":{"KOREA":"아, 나도 몰라! 수학쌤이 커트라인 이하를 몽땅 보충 대상으로 올려 버린 걸 어떡해!","JPN":"私だって知らないわ！　数学の先生が赤点は全員補習に来いって言うから仕方ないのよ！","ENG":"Ugh, whatever! It’s not my fault the math teacher forced everyone below the class average to take the make-up class!","TWN":"啊，我才不管！數學老師把不及格的人全部定為強制補習的對象了，我又能怎樣？"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHINNARAE_EXTRA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SHINNAJIN_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SHINNAJIN_EXTRA_NULL_NULL","text":{"KOREA":"어휴...... 그 머리로 사회 나가서 어떻게 살려고 그러냐?","JPN":"はあ……その頭で社会に出たらどうやって生きていくんだよ？","ENG":"Ugh... You’ll never survive out there once you graduate. Not with that brain...","TWN":"唉……妳這種腦袋，到底要怎麼出社會啊？"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHINNARAE_EXTRA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SHINNAJIN_EXTRA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L40_1","type":"dialog","speaker":"SHINNAJIN_EXTRA_NULL_NULL","text":{"KOREA":"걱정이다, 진짜.","JPN":"心配だよホント。","ENG":"Seriously, I worry about you sometimes.","TWN":"好令人不安啊，真是的。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHINNARAE_EXTRA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SHINNAJIN_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SHINNARAE_EXTRA_NULL_NULL","text":{"KOREA":"아니, 그런데 그렇게 잔소리하는 너는 왜 쫄랑쫄랑 따라오는 건데?","JPN":"そんなあんたこそ、ぶつぶつ言いながら、なんでついてくるわけ？","ENG":"Well, why are you tagging along anyway? Just to nag me?","TWN":"唉哟，這麼嘮叨，但你幹嘛要跟過來啊？"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHINNARAE_EXTRA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SHINNAJIN_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"SHINNARAE_EXTRA_NULL_NULL","text":{"KOREA":"잘나신 동생 나리께서는 성적우수생이라 보충 수업 같은 거 안 받아도 되잖아?","JPN":"成績優秀な弟さんは、補習なんてまったく縁のない話でしょ？","ENG":"I thought nerds like you didn’t have to take make up classes.","TWN":"我的好弟弟啊，你成績不是很好，不需要上補習班的嘛？"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHINNARAE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHINNAJIN_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SHINNAJIN_EXTRA_NULL_NULL","text":{"KOREA":"그그그그그, 그건!!","JPN":"そそそそそ、それは！！","ENG":"W-well, that’s because...","TWN":"那那那那那是因為！"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHINNARAE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHINNAJIN_EXTRA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"SHINNAJIN_EXTRA_NULL_NULL","text":{"KOREA":"요, 요즘 치안도 나, 나쁘고 침식 재난도 여기저기 터지고 하니까......","JPN":"さ、最近治安も悪いし、侵食災害もあちこちで起きてるから……","ENG":"I-it’s dangerous for girls to walk around by themselves these days... and there’s the corruption disaster too...","TWN":"最、最近治安不好嘛，到處都在發生侵蝕災難……"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHINNARAE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHINNAJIN_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SHINNAJIN_EXTRA_NULL_NULL","text":{"KOREA":"당연히 남자가 바, 바래다 줘야지!","JPN":"こんなときは、と、当然、男が送るべきだろ！","ENG":"S-so of course a man should escort you!","TWN":"當然要有男生護送你們啊！"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHINNARAE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHINNAJIN_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"SHINNARAE_EXTRA_NULL_NULL","text":{"KOREA":"아, 그러니까 이 누나가 걱정돼서 따라왔다고?","JPN":"あ、それはつまり、私が心配でついてきたってこと？","ENG":"Oh, so you're worried about your older sister now, are you?","TWN":"啊，是因為擔心我，所以才跟過來的？"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHINNARAE_EXTRA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SHINNAJIN_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"SHINNAJIN_EXTRA_NULL_NULL","text":{"KOREA":"제정신이야? 고릴라를 왜 걱정해?","JPN":"バカ言うな！　ゴリラは心配いらないだろ？","ENG":"O-of course not! You’re more dangerous than those monsters out there!","TWN":"妳瘋了嗎？為什麼我要擔心一隻猩猩？"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHINNARAE_EXTRA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SHINNAJIN_EXTRA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L48_1","type":"dialog","speaker":"SHINNARAE_EXTRA_NULL_NULL","text":{"KOREA":"이 망할 꼬맹이가 뭐라는 거야?!","JPN":"はあ？　チビのくせに、その口のきき方は何よ！？","ENG":"What did you say, you twerp?!","TWN":"你這臭小鬼說什麼！?"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHINNARAE_EXTRA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SHINNAJIN_EXTRA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L49_1","type":"dialog","speaker":"SHINNARAE_EXTRA_NULL_NULL","text":{"KOREA":"아주 지극 정성이다! 순정남 나셨네!","JPN":"すべては彼女のためですか！　一途過ぎて涙出そう！","ENG":"Well aren’t you a total gentleman! Look at you, Mr. Romance!","TWN":"真是太不會說話了，你這個純情少男！"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHINNARAE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHINNAJIN_EXTRA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L3_1","type":"dialog","speaker":"SHINNARAE_EXTRA_NULL_NULL","text":{"KOREA":"미나야. 이 버르장머리 없는 꼬마에게 현실을 좀 알려줘야 할 것 같아.","JPN":"ねぇ、ミナ。　この生意気なチビに現実を教えてあげましょう。","ENG":"Mina. I think we ought to teach this rude little boy a lesson about how the real world works.","TWN":"米娜啊，我覺得我們應該要讓這個沒禮貌的小鬼認清現實才對。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_STUDENT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SHINNARAE_EXTRA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L4_1","type":"dialog","speaker":"SHINNARAE_EXTRA_NULL_NULL","text":{"KOREA":"우리 동생께서 황송하게도 너 지켜주러 나오셨다는데 어떻게 생각해?","JPN":"うちの弟があなたのことを守りたくて、わざわざ駆け付けたそうだけど、どう思う？","ENG":"So what how do you feel about my little brother doing you the honors of escorting you?","TWN":"就讓我這個不成材的弟弟來保護妳，怎麼樣？"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_STUDENT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SHINNARAE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_STUDENT_NULL","text":{"KOREA":"......글쎄? 바래다 주는 건 고맙지만, 그래도 나진이가 상대면 내가 지켜줘야 할 것 같은데?","JPN":"……さあ？　送ってくれるのはありがたいけど、タクミなら私が守る側なんじゃないかな？","ENG":"Meh... I appreciate the gesture, but I feel like he’s the one who needs to be protected here.","TWN":"……嗯？雖然很謝謝你們送我，但如果對象是納金的話，應該是我去保護他才對吧？"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_STUDENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHINNARAE_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SHINNAJIN_EXTRA_NULL_NULL","text":{"KOREA":"그, 그건!!","JPN":"そ、それは！！","ENG":"B-but!","TWN":"這、這！！"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHINNAJIN_EXTRA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SHINNARAE_EXTRA_NULL_NULL","text":{"KOREA":"들었지? 꼬맹이가 누님들께 건방진 소리 해 봐야 이게 현실이란다.","JPN":"今の聞いた？　チビがお姉さま方に生意気言ったところで、これが現実よ。","ENG":"Hear that? You can try to sound macho all you want, but this is the reality you little punk.","TWN":"聽到沒？小鬼頭對姐姐們大放厥詞，終於認清現實了吧。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHINNARAE_EXTRA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_STUDENT_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_STUDENT_NULL","text":{"KOREA":"그래도...... 몇 년 지나고 나면 좀 더 듬직해지지 않을까?","JPN":"でも……何年か経ったら、今よりたくましくなるんじゃない？","ENG":"Still... I guess he could grow up to be a big, strong, reliable man in a few years.","TWN":"不過……幾年後，等你稍微穩重了一點，應該就可以了吧？"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHINNARAE_EXTRA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_STUDENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_STUDENT_NULL","text":{"KOREA":"그때는 잘 부탁해.","JPN":"その時は、よろしくね。","ENG":"I’ll be counting on you then.","TWN":"到時候就拜託你囉。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHINNARAE_EXTRA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_STUDENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SHINNAJIN_EXTRA_NULL_NULL","text":{"KOREA":"지지지지진짜? 나이 더 먹으면 괜찮다는 거지?","JPN":"ほ、ほほほほんとに？　もう少し年取れば大丈夫ってことだよね？","ENG":"R-really? Really, really? So I’ll have a chance when I’m older?","TWN":"……真真真真、真的嗎？再過幾年就可以了嗎……"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHINNAJIN_EXTRA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SHINNAJIN_EXTRA_NULL_NULL","text":{"KOREA":"나중에 딴말하면 안 돼!","JPN":"後で違うこと言ってもダメだからね！","ENG":"You can’t take it back later!","TWN":"不可以反悔喔！"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHINNAJIN_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_STUDENT_NULL","text":{"KOREA":"......아, 아니, 그렇게 진지하게 들으면 좀 곤란한데......","JPN":"……い、いや、そこまで真面目に受け取られても困るけど……","ENG":"W-well, you don’t need to take it that seriously...","TWN":"……呃，你這麼認真地問我，我會有點困擾的……"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHINNARAE_EXTRA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_STUDENT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"SHINNARAE_EXTRA_NULL_NULL","text":{"KOREA":"하아, 그러고 보니 미나 씨는 밀어붙이는 거에 약한 타입이셨죠.","JPN":"はあ、そういえばミナさんは押しに弱いタイプでございましたねー。","ENG":"Oh, I forgot how you’ve got a thing for confident guys, Mina.","TWN":"唉，這樣看來，米娜是對無理取鬧比較沒轍的類型呢。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHINNARAE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_STUDENT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"SHINNARAE_EXTRA_NULL_NULL","text":{"KOREA":"옆구리 시리니까 저리 가서 알콩달콩 살아 주세요.","JPN":"こんな干物女は放っといて、リア充様はどうぞ末永くお幸せに。","ENG":"Please don't mind me at all. You guys go ahead and live happily ever after without me.","TWN":"不要在這裡放閃啦，你們到一旁甜蜜地過日子去吧。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHINNARAE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_STUDENT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_STUDENT_NULL","text":{"KOREA":"넌 장난 좀 치지 말라니까, 진짜!","JPN":"もう、ふざけるのもいい加減にしなさいよ！","ENG":"Cut that out, would you?!","TWN":"妳別開玩笑了，真是的！"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHINNARAE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_STUDENT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"SHINNARAE_EXTRA_NULL_NULL","text":{"KOREA":"하하, 미안미안. 때리지 마.","JPN":"あははっ、ごめんごめん。叩かないでってば。","ENG":"Haha, sorry. Please don't hurt me.","TWN":"哈哈，抱歉抱歉，別打了。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHINNARAE_EXTRA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_STUDENT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"SHINNARAE_EXTRA_NULL_NULL","text":{"KOREA":"......음? 잠깐만, 잠깐만?","JPN":"……ん？　あれっ、待って？","ENG":"Huh? Hang on.","TWN":"……嗯？等等，等一下？"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHINNARAE_EXTRA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_STUDENT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"SHINNARAE_EXTRA_NULL_NULL","text":{"KOREA":"그런데 그건 뭐야?","JPN":"それは何？","ENG":"What’s that?","TWN":"妳那個是什麼啊？"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHINNARAE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_STUDENT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_STUDENT_NULL","text":{"KOREA":"뭐?","JPN":"えっ？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHINNARAE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_STUDENT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"SHINNARAE_EXTRA_NULL_NULL","text":{"KOREA":"그 시계, 못 보던 건데? 너 시계 안 차고 다녔잖아?","JPN":"その時計、見たことないかも？　普段、時計とかしてなかったじゃん？","ENG":"I haven’t seen that watch before. I thought you didn’t wear watches.","TWN":"那支手錶我從來都沒看過呀？妳之前不是沒戴錶嗎？"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHINNARAE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_STUDENT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_STUDENT_NULL","text":{"KOREA":"아, 이거? 이건......","JPN":"あ、これのこと？　これはね……","ENG":"Oh, this? This was...","TWN":"啊，這、這個……"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHINNARAE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_STUDENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SHINNAJIN_EXTRA_NULL_NULL","text":{"KOREA":"미, 미나 누나! 호...... 혹시 도하 형이 준 건 아니지?!","JPN":"ミ、ミナさん！　ま……まさか、例の奴からもらったんじゃないよね！？","ENG":"M-Mina! It’s... not a gift from Doha, is it?!","TWN":"米、米娜姐姐！那……該不會是道禾哥哥送的吧？！"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHINNAJIN_EXTRA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SHINNARAE_EXTRA_NULL_NULL","text":{"KOREA":"걔랑 경쟁하면 우리 나진이에게 희망이 별로 없는데......","JPN":"あーあ、あれがライバルなら、タクミは望み薄かもね……","ENG":"Ooh, if he’s also going for you my poor little brother doesn’t stand a chance...","TWN":"和他競爭的話，我們家納金就沒希望了……"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHINNARAE_EXTRA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_STUDENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SHINNARAE_EXTRA_NULL_NULL","text":{"KOREA":"분발해야겠다, 동생.","JPN":"タクミも奮発しないとね～。","ENG":"Looks like you’ve got to step up your game, Najin.","TWN":"你要加油一點啊。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHINNARAE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_STUDENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SHINNAJIN_EXTRA_NULL_NULL","text":{"KOREA":"아, 누나아! 좀!","JPN":"ちょ、やめろってば！","ENG":"Aw, come on! Stop teasing me!","TWN":"姐姐，噓！不要講了啦！"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHINNAJIN_EXTRA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YOOMINA_FENRIR_STUDENT_NULL","text":{"KOREA":"그, 그런 거 아냐.","JPN":"そ、そんなんじゃないから。","ENG":"N-no, it’s not.","TWN":"不、不是這樣的。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHINNARAE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_STUDENT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"YOOMINA_FENRIR_STUDENT_NULL","text":{"KOREA":"아침에 언니가 선물이라고 줬어.","JPN":"今朝、姉からもらったの。","ENG":"My sister gave it to me this morning as a present.","TWN":"這是早上姐姐給我的禮物。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHINNARAE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_STUDENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"YOOMINA_FENRIR_STUDENT_NULL","text":{"KOREA":"원래 자기가 차고 다니던 것 같은데......","JPN":"元々自分で使ってたみたいだけど……","ENG":"I think she used to wear it...","TWN":"這本來好像是姐姐一直戴著的東西……"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHINNARAE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_STUDENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"YOOMINA_FENRIR_STUDENT_NULL","text":{"KOREA":"오늘 꼭 차고 가라고 하더라고.","JPN":"今日は絶対つけていくように言われてね。","ENG":"But she asked me to wear it today, no matter what.","TWN":"她叫我今天一定要戴著這個。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHINNARAE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_STUDENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SHINNAJIN_EXTRA_NULL_NULL","text":{"KOREA":"그...... 그런 거야......?","JPN":"そ……そうなの……？","ENG":"Really? Is that it?","TWN":"是……是這樣嗎……？"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHINNAJIN_EXTRA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SHINNAJIN_EXTRA_NULL_NULL","text":{"KOREA":"다행이다...... 하아......","JPN":"よかった……ふう……","ENG":"Thank goodness... Phew...","TWN":"真是太好了……哈哈……"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHINNAJIN_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SHINNARAE_EXTRA_NULL_NULL","text":{"KOREA":"너네 언니? 정말? 그 콧대 높은 아가씨께서 선물을 하셨다고?","JPN":"ミナのお姉さん？　本当に？　あの高嶺の花からのプレゼントだって？","ENG":"Your sister? Really? Never thought a snob like your sister would give you a gift...","TWN":"妳的姐姐？真的？就是那個心高氣傲的大小姐送妳的禮物？"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHINNARAE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_STUDENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"YOOMINA_FENRIR_STUDENT_NULL","text":{"KOREA":"우리 언니 콧대 별로 안 높은데.......","JPN":"え……別に高嶺の花じゃないけど……","ENG":"My sister’s not a snob...","TWN":"我姐姐沒有很高傲吧……"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHINNARAE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_STUDENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"SHINNARAE_EXTRA_NULL_NULL","text":{"KOREA":"뭔 소리야? 동네에서 너네 언니에게 안 차여 본 남자가 없는데?","JPN":"何言ってんのよ、この辺であのお姉さんにふられてない男はいないんだから！","ENG":"Seriously? She pretty much rejected every guy in town.","TWN":"妳在說什麼啊？住在這附近的男人全都被你姐姐甩過。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHINNARAE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_STUDENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"SHINNARAE_EXTRA_NULL_NULL","text":{"KOREA":"내 추측엔 나진이도 너네 언니는 안 될 것 같으니까 꿩 대신 닭으로 너한테 들이대는 거 아닐까 싶어.","JPN":"私が思うに、タクミもあの人が本命だけど、到底手が届かないと思ってミナにアタックしてると思う。","ENG":"I bet Najin’s only hitting on you because he knows he doesn’t have a shot with your sister.","TWN":"我看妳姐姐應該是覺得納金不太行，所以就給了妳這支錶將就一下。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHINNARAE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_STUDENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"SHINNAJIN_EXTRA_NULL_NULL","text":{"KOREA":"아, 자꾸 뭔 소릴 하는 거야! 이 고릴라야!","JPN":"はあ！？　何バカなこと言ってんだよ！","ENG":"Cut that out! You monster!","TWN":"啊，妳又在說些什麼啊！妳這隻黑猩猩！"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHINNAJIN_EXTRA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SHINNAJIN_EXTRA_NULL_NULL","text":{"KOREA":"난 원래 미나 누나 일편단심이거든!","JPN":"僕は最初からミナさん一筋なんだよ！","ENG":"Mina’s my one and only!","TWN":"我本來就只對米娜姐姐唯一真心啊！"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHINNAJIN_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_STUDENT_NULL","text":{"KOREA":"......제발 부끄러우니까 길에서 그런 소리 크게 좀 하지 마, 둘 다.","JPN":"……ねえ、恥ずかしいから、2人とも道端でそんなこと大声で言わないでよ。","ENG":"Could the both of you please stop shouting things like that on the street? You're embarrassing me.","TWN":"……這種話別在大馬路上說得這麼大聲，你們兩個都是。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHINNARAE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_STUDENT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"SHINNARAE_EXTRA_NULL_NULL","text":{"KOREA":"어쨌든 그 언니께서 주신 거라면 당연히 명품이겠지? 구경 좀 하자!","JPN":"とにかく、あのお姉さんのなら、当然ブランドものでしょ？　ちょっと見せてよ！","ENG":"Anyway, it must be a fancy watch, coming from your sister. Let me see!","TWN":"不管怎樣，你姐姐給的肯定是名牌吧？給我看看！"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHINNARAE_EXTRA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SHINNARAE_EXTRA_NULL_NULL","text":{"KOREA":"어디 거야? 스위스? 이태리? 독일?","JPN":"どこのやつ？　スイス？　イタリア？　ドイツ？","ENG":"Where's it from? Switzerland? Italy? Germany?","TWN":"哪個國家的啊？瑞士、義大利、德國？"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHINNARAE_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_STUDENT_NULL","text":{"KOREA":"그, 그런 건 아닌 것 같은데....... 애초에 상표도 없고.","JPN":"そ、そういうのじゃないと思う……そもそもブランド名とかもついてないし。","ENG":"I-I don’t think it’s that sort of watch... There’s no brand logo either.","TWN":"好像都不是……它上面也沒有商標。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_STUDENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_STUDENT_NULL","text":{"KOREA":"좀 이상해. 시간도 잘 안 맞는 것 같고......","JPN":"ちょっと変なんだよね。時間も合ってないみたいだし……","ENG":"It’s kind of weird, actually. The time seems to be off too.","TWN":"而且它看起來有點奇怪，時間似乎不太準……"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_STUDENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_STUDENT_NULL","text":{"KOREA":"고장난 건 아닌 것 같은데.","JPN":"壊れてるわけじゃなさそうだけど。","ENG":"It doesn’t seem to be broken though.","TWN":"但又好像沒有故障。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_STUDENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_STUDENT_NULL","text":{"KOREA":"......잘 모르겠어.","JPN":"……なんでだろう。","ENG":"I’m not sure what’s wrong with it...","TWN":"……真搞不懂。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_STUDENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_STUDENT_NULL","text":{"KOREA":"저녁에 돌아가면 물어 봐야지.","JPN":"家に帰ったら聞いてみよう。","ENG":"I guess I’ll ask my sister later.","TWN":"晚上回去時問問她好了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};